1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // Edge: empty
6	  it("empty item list quote → premium 5 G (only processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // Base premiums for single items (no modifiers, customer with no history triggers first-insurance surcharge; use loyalty 0 / no special)
15	  // We'll use a customer with yearsWithMHPCO=0 and treat first item — but first insurance surcharge and 10% surcharge apply.
16	  // For purely "base premium" verification we need cases that exercise base only. Use integration-style descriptions.
17	
18	  // Building block of 3 alike components — base premium only (these tests need a way to see just base premium; we instead use full quote with conditions that zero out other modifiers)
19	  // To verify base premium logic we use a long-standing customer scenario or just check the resulting premium reflects building block math.
20	
21	  // Building block examples (use customer 0yrs, first quote, no curse, no enchant → only first-insurance 10% + 5G fee)
22	  it("quote 2 runes for new customer → premium = 50 base + 10% first insurance + 5 fee = 60 G", () => {
23	    const result = runScenario({
24	      customer: { yearsWithMHPCO: 0 },
25	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
26	    });
27	    expect(result).toEqual({ results: [{ premium: 60 }] });
28	  });
29	  it("quote 3 runes (block applies) → premium = 60 base + 10% first insurance + 5 fee = 71 G", () => {
30	    const result = runScenario({
31	      customer: { yearsWithMHPCO: 0 },
32	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] }],
33	    });
34	    expect(result).toEqual({ results: [{ premium: 71 }] });
35	  });
36	  it("quote 4 runes (no block — block requires exactly 3) → premium = 100 base + 10% first insurance + 5 fee = 115 G", () => {
37	    const result = runScenario({
38	      customer: { yearsWithMHPCO: 0 },
39	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }] }],
40	    });
41	    expect(result).toEqual({ results: [{ premium: 115 }] });
42	  });
43	  it("quote 7 runes → premium = 175 base + 10% first insurance + 5 fee = 198 G (rounded up from 197.5)", () => {
44	    const items = Array.from({ length: 7 }, () => ({ type: "rune" }));
45	    const result = runScenario({
46	      customer: { yearsWithMHPCO: 0 },
47	      steps: [{ op: "quote", items }],
48	    });
49	    expect(result).toEqual({ results: [{ premium: 198 }] });
50	  });
51	
52	  // Alike components clarification
53	  it("quote 2 runes + 1 moonstone → no block (different types), base 75 G → premium 88 G", () => {
54	    const result = runScenario({
55	      customer: { yearsWithMHPCO: 0 },
56	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }] }],
57	    });
58	    expect(result).toEqual({ results: [{ premium: 88 }] });
59	  });
60	  it("quote 3 runes + 3 moonstones → two separate blocks, base 120 G → premium 137 G", () => {
61	    const result = runScenario({
62	      customer: { yearsWithMHPCO: 0 },
63	      steps: [{
64	        op: "quote",
65	        items: [
66	          { type: "rune" }, { type: "rune" }, { type: "rune" },
67	          { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" },
68	        ],
69	      }],
70	    });
71	    expect(result).toEqual({ results: [{ premium: 137 }] });
72	  });
73	
74	  // Single item base premiums (verify each item type)
75	  it("quote single sword (new customer) → 100 + 10 + 5 = 115 G", () => {
76	    const result = runScenario({
77	      customer: { yearsWithMHPCO: 0 },
78	      steps: [{ op: "quote", items: [{ type: "sword" }] }],
79	    });
80	    expect(result).toEqual({ results: [{ premium: 115 }] });
81	  });
82	  it("quote single amulet (new customer) → 60 + 6 + 5 = 71 G", () => {
83	    const result = runScenario({
84	      customer: { yearsWithMHPCO: 0 },
85	      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
86	    });
87	    expect(result).toEqual({ results: [{ premium: 71 }] });
88	  });
89	  it("quote single staff (new customer) → 80 + 8 + 5 = 93 G", () => {
90	    const result = runScenario({
91	      customer: { yearsWithMHPCO: 0 },
92	      steps: [{ op: "quote", items: [{ type: "staff" }] }],
93	    });
94	    expect(result).toEqual({ results: [{ premium: 93 }] });
95	  });
96	  it("quote single potion (new customer) → 40 + 4 + 5 = 49 G", () => {
97	    const result = runScenario({
98	      customer: { yearsWithMHPCO: 0 },
99	      steps: [{ op: "quote", items: [{ type: "potion" }] }],
100	    });
101	    expect(result).toEqual({ results: [{ premium: 49 }] });
102	  });
103	
104	  // Modifier thresholds
105	  it("customer with exactly 2 years gets loyalty discount", () => {
106	    // sword: 100 base; loyalty -20% = 80; first-insurance +10% = 88; +5 fee = 93
107	    const result = runScenario({
108	      customer: { yearsWithMHPCO: 2 },
109	      steps: [{ op: "quote", items: [{ type: "sword" }] }],
110	    });
111	    expect(result).toEqual({ results: [{ premium: 93 }] });
112	  });
113	  it("sword with enchantment exactly 5 gets high-enchantment surcharge", () => {
114	    // sword: 100 base + 30 high-ench = 130; +10% first ins = 143; +5 = 148
115	    const result = runScenario({
116	      customer: { yearsWithMHPCO: 0 },
117	      steps: [{ op: "quote", items: [{ type: "sword", enchantment: 5 }] }],
118	    });
119	    expect(result).toEqual({ results: [{ premium: 148 }] });
120	  });
121	  it("sword with enchantment 4 has no high-enchantment surcharge", () => {
122	    const result = runScenario({
123	      customer: { yearsWithMHPCO: 0 },
124	      steps: [{ op: "quote", items: [{ type: "sword", enchantment: 4 }] }],
125	    });
126	    expect(result).toEqual({ results: [{ premium: 115 }] });
127	  });
128	  it("sword cursed and enchantment 5 → both surcharges apply", () => {
129	    // 100 base + 50 curse + 30 high-ench = 180; +10% first = 198; +5 = 203
130	    const result = runScenario({
131	      customer: { yearsWithMHPCO: 0 },
132	      steps: [{ op: "quote", items: [{ type: "sword", enchantment: 5, cursed: true }] }],
133	    });
134	    expect(result).toEqual({ results: [{ premium: 203 }] });
135	  });
136	
137	  // Modifier scope on multi-item policies
138	  it.todo("policy of cursed sword + plain amulet → 100 + 60 base = 160, cursed adds 50 (50% of sword only) = 210 before fee/other modifiers");
139	
140	  // Integration examples
141	  it.todo("newcomer with cursed sword (steel, enchantment 3, 0 years) → premium 165 G");
142	  it.todo("long-standing customer's second contract (3 years, cursed sword enchantment 7, second quote) → premium 160 G");
143	
144	  // First insurance applies per item regardless of follow-up
145	  it.todo("each item in a quote is first insurance regardless of customer history");
146	
147	  // Rounding — premium
148	  it.todo("premium yielding 197.5 G is rounded up to 198 G (MHPCO's favor)");
149	
150	  // Claim: standard reimbursement
151	  it.todo("regular sword damage 500 → payout 400 (full minus 100 deductible)");
152	  it.todo("rune (no enchantment/material), damage 200 → payout 100");
153	
154	  // High enchantment vs dragon material
155	  it.todo("dragon-material sword, enchantment 8, damage 1000 → payout 400 (50% then deductible)");
156	  it.todo("dragon-material sword, enchantment 9, damage 1000 → payout 400 (both clauses; 50% wins, then deductible)");
157	  it.todo("dragon-material sword, enchantment 5, damage 800 → payout 700 (only dragon clause; full then deductible)");
158	  it.todo("steel sword, enchantment 9, damage 1000 → payout 400 (50% then deductible)");
159	
160	  // Deductible per damage event
161	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 (deductible per item)");
162	
163	  // Multiple items of same type
164	  it.todo("policy covers two swords → insurance sum 2000 G, cap 4000 G");
165	  it.todo("dragon attack damages both swords (two entries) → each entry has its own deductible");
166	  it.todo("damages contains two sword entries but only one sword insured → CLI rejects with non-zero status");
167	
168	  // Cap exhaustion
169	  it.todo("sword + amulet policy → insurance sum 1600 G, cap 3200 G");
170	  it.todo("cursed sword premium modifiers don't change cap → cap 2000 G");
171	  it.todo("sword + 3 runes (block) → insurance sum 1750 G; block discount doesn't reduce insurance sum");
172	  it.todo("two successive 1500 claims on sword (cap 2000) → first payout 1400 (cap remaining 600), second 600 (cap 0)");
173	
174	  // Rounding — payout
175	  it.todo("payout yielding 350.5 G is rounded down to 350 G (MHPCO's favor)");
176	
177	  // Error edge cases
178	  it.todo("unknown item type in quote → CLI exits non-zero with stderr; no results on stdout");
179	  it.todo("claim damage references item not in policy → CLI exits non-zero with stderr");
180	  it.todo("claim damage with negative amount → CLI exits non-zero with stderr");
181	});
