1	type Item = { type: string; enchantment?: number; cursed?: boolean; material?: string };
2	type QuoteStep = { op: "quote"; items: Item[] };
3	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
4	
5	const PROCESSING_FEE = 5;
6	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
7	const THREE_ALIKE_BLOCK_PREMIUM = 60;
8	
9	type ItemTypeSpec = { basePremium: number; isComponent: boolean };
10	
11	const ITEM_TYPES: Record<string, ItemTypeSpec> = {
12	  // Whole items
13	  sword: { basePremium: 100, isComponent: false },
14	  amulet: { basePremium: 60, isComponent: false },
15	  staff: { basePremium: 80, isComponent: false },
16	  potion: { basePremium: 40, isComponent: false },
17	  // Components (eligible for 3-alike block premium)
18	  rune: { basePremium: 25, isComponent: true },
19	  moonstone: { basePremium: 25, isComponent: true },
20	};
21	
22	const percentOf = (amount: number, percent: number): number => (amount * percent) / 100;
23	
24	const countByType = (items: Item[]): Map<string, number> =>
25	  items.reduce(
26	    (counts, item) => counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
27	    new Map<string, number>(),
28	  );
29	
30	const basePremiumForGroup = (type: string, count: number): number => {
31	  const spec = ITEM_TYPES[type];
32	  if (spec.isComponent && count === 3) return THREE_ALIKE_BLOCK_PREMIUM;
33	  return count * spec.basePremium;
34	};
35	
36	const HIGH_ENCHANTMENT_SURCHARGE_PERCENT = 30;
37	const HIGH_ENCHANTMENT_THRESHOLD = 5;
38	const CURSE_SURCHARGE_PERCENT = 50;
39	
40	// Each surcharge rule receives the item and its base premium and returns
41	// the surcharge amount in gold (0 when the rule does not apply).
42	type ItemSurchargeRule = (item: Item, itemBase: number) => number;
43	
44	const ITEM_SURCHARGE_RULES: ItemSurchargeRule[] = [
45	  (item, itemBase) =>
46	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
47	      ? percentOf(itemBase, HIGH_ENCHANTMENT_SURCHARGE_PERCENT)
48	      : 0,
49	  (item, itemBase) =>
50	    item.cursed ? percentOf(itemBase, CURSE_SURCHARGE_PERCENT) : 0,
51	];
52	
53	const itemSurcharges = (item: Item): number => {
54	  const itemBase = ITEM_TYPES[item.type].basePremium;
55	  return ITEM_SURCHARGE_RULES.reduce((sum, rule) => sum + rule(item, itemBase), 0);
56	};
57	
58	const basePremiumFor = (items: Item[]): number => {
59	  const groupBase = [...countByType(items)]
60	    .reduce((sum, [type, count]) => sum + basePremiumForGroup(type, count), 0);
61	  const itemSurchargeSum = items.reduce((sum, item) => sum + itemSurcharges(item), 0);
62	  return groupBase + itemSurchargeSum;
63	};
64	
65	const applyFirstInsuranceSurcharge = (premium: number): number =>
66	  premium + percentOf(premium, FIRST_INSURANCE_SURCHARGE_PERCENT);
67	
68	const LOYALTY_DISCOUNT_PERCENT = 20;
69	const LOYALTY_MIN_YEARS = 2;
70	
71	const applyLoyaltyDiscount = (premium: number, yearsWithMHPCO: number): number =>
72	  yearsWithMHPCO >= LOYALTY_MIN_YEARS ? premium - percentOf(premium, LOYALTY_DISCOUNT_PERCENT) : premium;
73	
74	const quotePremium = (items: Item[], yearsWithMHPCO: number): number => {
75	  const afterLoyalty = applyLoyaltyDiscount(basePremiumFor(items), yearsWithMHPCO);
76	  return Math.ceil(applyFirstInsuranceSurcharge(afterLoyalty)) + PROCESSING_FEE;
77	};
78	
79	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
80	  const years = scenario.customer.yearsWithMHPCO;
81	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items, years) }));
82	  return { results };
83	};
